class Solution {
public:
    vector<int> popcountDepth(vector<long long>& nums, vector<vector<long long>>& queries) {
        const int MAXD = 5;
        int n = nums.size();
        vector<int> depth(n);
        auto getDepth = [](long long x) -> int {
            int d = 0;
            while (x != 1) {
                x = __builtin_popcountll(x);
                ++d;
            }
            return d;
        };
        for (int i = 0; i < n; ++i) depth[i] = getDepth(nums[i]);

        vector<vector<int>> fen(MAXD + 1, vector<int>(n + 2));
        auto add = [&](int k, int idx, int delta) {
            for (++idx; idx <= n; idx += idx & -idx) fen[k][idx] += delta;
        };
        auto sum = [&](int k, int idx) {
            int res = 0;
            for (++idx; idx > 0; idx -= idx & -idx) res += fen[k][idx];
            return res;
        };
        auto range = [&](int k, int l, int r) { return sum(k, r) - sum(k, l - 1); };

        for (int i = 0; i < n; ++i) add(depth[i], i, 1);

        vector<int> ans;
        for (auto& q : queries) {
            if (q[0] == 1) {
                int l = q[1], r = q[2], k = q[3];
                if (k < 0 || k > MAXD) ans.push_back(0);
                else ans.push_back(range(k, l, r));
            } else {
                int idx = q[1];
                long long val = q[2];
                int oldD = depth[idx];
                int newD = getDepth(val);
                if (oldD != newD) {
                    add(oldD, idx, -1);
                    add(newD, idx, 1);
                    depth[idx] = newD;
                }
            }
        }
        return ans;
    }
};
